import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Paper, 
  Typography, 
  Box, 
  Table, 
  TableBody, 
  TableCell, 
  TableContainer, 
  TableHead, 
  TableRow,
  TablePagination,
  Chip,
  TextField,
  InputAdornment,
  CircularProgress,
  Alert,
  Toolbar,
  IconButton,
  Menu,
  MenuItem,
  FormControl,
  InputLabel,
  Select,
  Grid,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Divider,
} from '@mui/material';
import {
  Search,
  FilterList,
  ArrowUpward,
  ArrowDownward,
  SwapHoriz,
  ContentCopy,
  Info,
  Download
} from '@mui/icons-material';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Transactions = () => {
  const navigate = useNavigate();
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [totalCount, setTotalCount] = useState(0);
  const [searchTerm, setSearchTerm] = useState('');
  const [anchorEl, setAnchorEl] = useState(null);
  const [filters, setFilters] = useState({
    type: 'all',
    dateRange: 'all',
    status: 'all',
    wallet: 'all'
  });
  const [wallets, setWallets] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);
  const [detailsOpen, setDetailsOpen] = useState(false);
  const [copySuccess, setCopySuccess] = useState('');

  useEffect(() => {
    fetchTransactions();
    fetchWallets();
  }, [page, rowsPerPage, filters]);

  const fetchTransactions = async () => {
    setLoading(true);
    setError(null);

    try {
      // Construct query parameters
      const params = new URLSearchParams({
        page: page + 1, // API typically uses 1-based indexing
        limit: rowsPerPage,
      });

      // Add filters
      if (filters.type !== 'all') params.append('type', filters.type);
      if (filters.status !== 'all') params.append('status', filters.status);
      if (filters.wallet !== 'all') params.append('wallet_id', filters.wallet);
      if (filters.dateRange !== 'all') {
        const now = new Date();
        let startDate;

        switch (filters.dateRange) {
          case '7days':
            startDate = new Date(now.setDate(now.getDate() - 7));
            break;
          case '30days':
            startDate = new Date(now.setDate(now.getDate() - 30));
            break;
          case '90days':
            startDate = new Date(now.setDate(now.getDate() - 90));
            break;
          default:
            break;
        }

        if (startDate) {
          params.append('start_date', startDate.toISOString().split('T')[0]);
        }
      }

      // Add search term
      if (searchTerm) params.append('search', searchTerm);

      const response = await axios.get(`/transaction/?${params.toString()}`);
      setTransactions(response.data.transactions || response.data);
      setTotalCount(response.data.total_count || response.data.length);
    } catch (err) {
      console.error('Error fetching transactions:', err);
      setError('Failed to load transactions. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const fetchWallets = async () => {
    try {
      const response = await axios.get('/wallet/');
      setWallets(response.data);
    } catch (err) {
      console.error('Error fetching wallets:', err);
    }
  };

  const handleChangePage = (event, newPage) => {
    setPage(newPage);
  };

  const handleChangeRowsPerPage = (event) => {
    setRowsPerPage(parseInt(event.target.value, 10));
    setPage(0);
  };

  const handleSearchChange = (e) => {
    setSearchTerm(e.target.value);
  };

  const handleSearch = (e) => {
    if (e.key === 'Enter') {
      fetchTransactions();
    }
  };

  const handleFilterMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleFilterMenuClose = () => {
    setAnchorEl(null);
  };

  const handleFilterChange = (name, value) => {
    setFilters({
      ...filters,
      [name]: value
    });
    setPage(0); // Reset to first page when filter changes
  };

  const handleViewDetails = (transaction) => {
    setSelectedTransaction(transaction);
    setDetailsOpen(true);
  };

  const handleCloseDetails = () => {
    setDetailsOpen(false);
  };

  const copyToClipboard = (text, type) => {
    navigator.clipboard.writeText(text).then(
      () => {
        setCopySuccess(`${type} copied!`);
        setTimeout(() => setCopySuccess(''), 2000);
      },
      () => {
        setCopySuccess('Failed to copy');
      }
    );
  };

  const getStatusChip = (status) => {
    let color = 'default';

    switch (status.toUpperCase()) {
      case 'COMPLETED':
        color = 'success';
        break;
      case 'PENDING':
        color = 'warning';
        break;
      case 'FAILED':
        color = 'error';
        break;
      default:
        color = 'default';
    }

    return <Chip label={status} color={color} size="small" />;
  };

  const getTypeIcon = (type) => {
    if (type === 'DEPOSIT' || type === 'RECEIVE') return <ArrowDownward fontSize="small" color="success" />;
    if (type === 'WITHDRAWAL' || type === 'SEND') return <ArrowUpward fontSize="small" color="error" />;
    return <SwapHoriz fontSize="small" color="primary" />;
  };

  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' };
    return new Date(dateString).toLocaleDateString('en-US', options);
  };

  const formatCurrency = (amount, currency = 'USD') => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency
    }).format(amount);
  };

  const getWalletName = (walletId) => {
    const wallet = wallets.find(w => w.id === walletId);
    return wallet ? wallet.name : 'Unknown Wallet';
  };

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Paper sx={{ width: '100%', mb: 2 }}>
          <Toolbar sx={{ pl: { sm: 2 }, pr: { xs: 1, sm: 1 } }}>
            <Typography
              sx={{ flex: '1 1 100%' }}
              variant="h5"
              component="div"
            >
              Transactions
            </Typography>

            <Box sx={{ display: 'flex', alignItems: 'center' }}>
              <TextField
                margin="dense"
                placeholder="Search transactions..."
                variant="outlined"
                size="small"
                value={searchTerm}
                onChange={handleSearchChange}
                onKeyPress={handleSearch}
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Search />
                    </InputAdornment>
                  ),
                }}
                sx={{ mr: 2, width: '220px' }}
              />

              <IconButton onClick={handleFilterMenuOpen}>
                <FilterList />
              </IconButton>

              <Menu
                anchorEl={anchorEl}
                open={Boolean(anchorEl)}
                onClose={handleFilterMenuClose}
                sx={{ mt: 1 }}
              >
                <Box sx={{ px: 2, py: 1, width: 200 }}>
                  <FormControl fullWidth margin="dense" size="small">
                    <InputLabel id="transaction-type-label">Type</InputLabel>
                    <Select
                      labelId="transaction-type-label"
                      value={filters.type}
                      label="Type"
                      onChange={(e) => handleFilterChange('type', e.target.value)}
                    >
                      <MenuItem value="all">All Types</MenuItem>
                      <MenuItem value="SEND">Send</MenuItem>
                      <MenuItem value="RECEIVE">Receive</MenuItem>
                      <MenuItem value="DEPOSIT">Deposit</MenuItem>
                      <MenuItem value="WITHDRAWAL">Withdrawal</MenuItem>
                      <MenuItem value="EXCHANGE">Exchange</MenuItem>
                    </Select>
                  </FormControl>

                  <FormControl fullWidth margin="dense" size="small">
                    <InputLabel id="transaction-date-label">Date Range</InputLabel>
                    <Select
                      labelId="transaction-date-label"
                      value={filters.dateRange}
                      label="Date Range"
                      onChange={(e) => handleFilterChange('dateRange', e.target.value)}
                    >
                      <MenuItem value="all">All Time</MenuItem>
                      <MenuItem value="7days">Last 7 Days</MenuItem>
                      <MenuItem value="30days">Last 30 Days</MenuItem>
                      <MenuItem value="90days">Last 90 Days</MenuItem>
                    </Select>
                  </FormControl>

                  <FormControl fullWidth margin="dense" size="small">
                    <InputLabel id="transaction-status-label">Status</InputLabel>
                    <Select
                      labelId="transaction-status-label"
                      value={filters.status}
                      label="Status"
                      onChange={(e) => handleFilterChange('status', e.target.value)}
                    >
                      <MenuItem value="all">All Statuses</MenuItem>
                      <MenuItem value="COMPLETED">Completed</MenuItem>
                      <MenuItem value="PENDING">Pending</MenuItem>
                      <MenuItem value="FAILED">Failed</MenuItem>
                    </Select>
                  </FormControl>

                  <FormControl fullWidth margin="dense" size="small">
                    <InputLabel id="transaction-wallet-label">Wallet</InputLabel>
                    <Select
                      labelId="transaction-wallet-label"
                      value={filters.wallet}
                      label="Wallet"
                      onChange={(e) => handleFilterChange('wallet', e.target.value)}
                    >
                      <MenuItem value="all">All Wallets</MenuItem>
                      {wallets.map((wallet) => (
                        <MenuItem key={wallet.id} value={wallet.id}>
                          {wallet.name}
                        </MenuItem>
                      ))}
                    </Select>
                  </FormControl>

                  <Box sx={{ mt: 2, display: 'flex', justifyContent: 'flex-end' }}>
                    <Button 
                      variant="outlined" 
                      size="small"
                      onClick={() => {
                        setFilters({
                          type: 'all',
                          dateRange: 'all',
                          status: 'all',
                          wallet: 'all'
                        });
                        handleFilterMenuClose();
                      }}
                    >
                      Reset
                    </Button>
                    <Button 
                      variant="contained" 
                      size="small" 
                      sx={{ ml: 1 }}
                      onClick={handleFilterMenuClose}
                    >
                      Apply
                    </Button>
                  </Box>
                </Box>
              </Menu>
            </Box>
          </Toolbar>

          {copySuccess && (
            <Alert severity="success" sx={{ mx: 2 }}>
              {copySuccess}
            </Alert>
          )}

          {error && (
            <Alert severity="error" sx={{ m: 2 }}>
              {error}
            </Alert>
          )}

          <TableContainer>
            {loading ? (
              <Box display="flex" justifyContent="center" alignItems="center" py={4}>
                <CircularProgress />
              </Box>
            ) : transactions.length === 0 ? (
              <Box textAlign="center" py={4}>
                <Typography variant="h6" color="text.secondary">
                  No transactions found
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
                  Try adjusting your filters or make your first transaction
                </Typography>
                <Button 
                  variant="contained" 
                  sx={{ mt: 2 }}
                  onClick={() => navigate('/send')}
                >
                  Send Money
                </Button>
              </Box>
            ) : (
              <Table aria-label="transactions table">
                <TableHead>
                  <TableRow>
                    <TableCell>Type</TableCell>
                    <TableCell>Date</TableCell>
                    <TableCell>Description</TableCell>
                    <TableCell>Amount</TableCell>
                    <TableCell>Wallet</TableCell>
                    <TableCell>Status</TableCell>
                    <TableCell align="right">Actions</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {transactions.map((transaction) => (
                    <TableRow key={transaction.id} hover>
                      <TableCell>
                        <Box display="flex" alignItems="center">
                          {getTypeIcon(transaction.type)}
                          <Typography variant="body2" sx={{ ml: 1 }}>
                            {transaction.type}
                          </Typography>
                        </Box>
                      </TableCell>
                      <TableCell>{formatDate(transaction.timestamp)}</TableCell>
                      <TableCell>{transaction.description || "—"}</TableCell>
                      <TableCell>{formatCurrency(transaction.amount, transaction.currency)}</TableCell>
                      <TableCell>{getWalletName(transaction.source_wallet_id)}</TableCell>
                      <TableCell>{getStatusChip(transaction.status)}</TableCell>
                      <TableCell align="right">
                        <IconButton size="small" onClick={() => handleViewDetails(transaction)}>
                          <Info fontSize="small" />
                        </IconButton>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            )}
          </TableContainer>

          <TablePagination
            rowsPerPageOptions={[10, 25, 50]}
            component="div"
            count={totalCount}
            rowsPerPage={rowsPerPage}
            page={page}
            onPageChange={handleChangePage}
            onRowsPerPageChange={handleChangeRowsPerPage}
          />
        </Paper>
      </Box>

      {/* Transaction Details Dialog */}
      <Dialog open={detailsOpen} onClose={handleCloseDetails} maxWidth="sm" fullWidth>
        {selectedTransaction && (
          <>
            <DialogTitle>
              Transaction Details
              <IconButton
                aria-label="close"
                onClick={handleCloseDetails}
                sx={{
                  position: 'absolute',
                  right: 8,
                  top: 8,
                }}
              >
                <Info />
              </IconButton>
            </DialogTitle>
            <DialogContent>
              <Box mb={2}>
                <Typography variant="overline" color="text.secondary">
                  Transaction ID
                </Typography>
                <Box display="flex" alignItems="center">
                  <Typography variant="body2" sx={{ mr: 1, wordBreak: 'break-all' }}>
                    {selectedTransaction.id}
                  </Typography>
                  <IconButton 
                    size="small"
                    onClick={() => copyToClipboard(selectedTransaction.id, 'Transaction ID')}
                  >
                    <ContentCopy fontSize="small" />
                  </IconButton>
                </Box>
              </Box>

              <Divider sx={{ my: 2 }} />

              <Grid container spacing={2}>
                <Grid item xs={6}>
                  <Typography variant="overline" color="text.secondary">
                    Type
                  </Typography>
                  <Typography variant="body1">
                    {selectedTransaction.type}
                  </Typography>
                </Grid>

                <Grid item xs={6}>
                  <Typography variant="overline" color="text.secondary">
                    Status
                  </Typography>
                  <Box>
                    {getStatusChip(selectedTransaction.status)}
                  </Box>
                </Grid>

                <Grid item xs={6}>
                  <Typography variant="overline" color="text.secondary">
                    Amount
                  </Typography>
                  <Typography variant="body1">
                    {formatCurrency(selectedTransaction.amount, selectedTransaction.currency)}
                  </Typography>
                </Grid>

                <Grid item xs={6}>
                  <Typography variant="overline" color="text.secondary">
                    Fee
                  </Typography>
                  <Typography variant="body1">
                    {formatCurrency(selectedTransaction.fee || 0, selectedTransaction.currency)}
                  </Typography>
                </Grid>

                <Grid item xs={12}>
                  <Typography variant="overline" color="text.secondary">
                    Date & Time
                  </Typography>
                  <Typography variant="body1">
                    {formatDate(selectedTransaction.timestamp)}
                  </Typography>
                </Grid>

                <Grid item xs={12}>
                  <Typography variant="overline" color="text.secondary">
                    Source Wallet
                  </Typography>
                  <Typography variant="body1">
                    {getWalletName(selectedTransaction.source_wallet_id)}
                  </Typography>
                  <Typography variant="body2" color="text.secondary" sx={{ wordBreak: 'break-all' }}>
                    {selectedTransaction.source_wallet_id}
                  </Typography>
                </Grid>

                {selectedTransaction.recipient_address && (
                  <Grid item xs={12}>
                    <Typography variant="overline" color="text.secondary">
                      Recipient Address
                    </Typography>
                    <Box display="flex" alignItems="center">
                      <Typography variant="body2" sx={{ mr: 1, wordBreak: 'break-all' }}>
                        {selectedTransaction.recipient_address}
                      </Typography>
                      <IconButton 
                        size="small"
                        onClick={() => copyToClipboard(selectedTransaction.recipient_address, 'Recipient Address')}
                      >
                        <ContentCopy fontSize="small" />
                      </IconButton>
                    </Box>
                  </Grid>
                )}

                {selectedTransaction.description && (
                  <Grid item xs={12}>
                    <Typography variant="overline" color="text.secondary">
                      Description
                    </Typography>
                    <Typography variant="body1">
                      {selectedTransaction.description}
                    </Typography>
                  </Grid>
                )}
              </Grid>
            </DialogContent>
            <DialogActions>
              <Button 
                startIcon={<Download />}
                onClick={handleCloseDetails}
              >
                Export
              </Button>
              <Button 
                variant="contained" 
                onClick={handleCloseDetails}
              >
                Close
              </Button>
            </DialogActions>
          </>
        )}
      </Dialog>
    </Container>
  );
};

export default Transactions;
